function sourcePages(paper,question,part){if(paper.id==='asc24'||paper.id==='sgs25'){let page=part.page||paper.schema.find(group=>group.q===question)?.page||Math.max(2,question-9);return {questionPage:page,solutionPage:page}}return {questionPage:examPages[question],solutionPage:solutionPartPages[part.id]||solutionPages[question]}}
function topicArea(topic,course=''){if(/Standard/.test(course)){if(/financial/i.test(topic))return 'Financial mathematics';if(/network/i.test(topic))return 'Networks';if(/statistical|probability/i.test(topic))return 'Statistics';if(/measurement|trig|rate/i.test(topic))return 'Measurement';return 'Algebra'}if(/vector|projectile/i.test(topic))return 'Vectors';if(/proof|induction/i.test(topic))return 'Proof';if(/trig/i.test(topic))return 'Trigonometric functions';if(/combin|binomial theorem/i.test(topic))return 'Combinatorics';if(/distribution|statistical|sampling|probability/i.test(topic))return 'Statistical analysis';if(/polynomial|function|graph/i.test(topic))return 'Functions';return 'Calculus'}
function areaPercent(area){let score=state.topicScores[area];return score&&score.max?Math.round(score.earned/score.max*100):null}
const defaultProfile={name:'Daniel Cao',year:'Year 12',course:'Mathematics Extension 1',goal:'Score 85%+ in my HSC trials',weekly:'3 papers per week',focus:['Vectors','Combinatorics']};
function loadProfile(){try{return {...defaultProfile,...JSON.parse(localStorage.getItem('arc-profile')||'{}')}}catch{return {...defaultProfile}}}
function loadBank(){try{return JSON.parse(localStorage.getItem('arc-question-bank')||'[]')}catch{return []}}
function loadAttemptHistory(){try{return JSON.parse(localStorage.getItem('arc-attempt-history')||'[]')}catch{return []}}
function persistLearningData(){localStorage.setItem('arc-question-bank',JSON.stringify(wrongQuestions));localStorage.setItem('arc-attempt-history',JSON.stringify(state.attemptHistory))}
function attemptCourse(attempt){return papers.find(p=>p.id===attempt.paperId)?.course||attempt.course||'Unknown'}
function rebuildTopicScores(){let combined={};state.attemptHistory.filter(attempt=>attemptCourse(attempt)===state.statsCourse).forEach(attempt=>Object.entries(attempt.topicScores||{}).forEach(([area,score])=>{if(!combined[area])combined[area]={earned:0,max:0};combined[area].earned+=score.earned;combined[area].max+=score.max}));state.topicScores=combined}
function resultCourseTabs(){return `<div class="course-tabs">${[...new Set(papers.map(p=>p.course))].map(course=>`<button class="course-tab ${state.statsCourse===course?'active':''}" data-stats-course="${course}">${course}</button>`).join('')}</div>`}
function esc(value){return String(value??'').replace(/[&<>'"]/g,char=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[char]))}
function initials(name){return name.trim().split(/\s+/).slice(0,2).map(part=>part[0]).join('').toUpperCase()||'S'}
