function layout(content){let p=state.profile;app.innerHTML=`<div class="shell"><aside class="sidebar"><div class="logo"><i class="logo-mark"></i><span class="logo-text">Arc</span></div><nav>${nav.map(n=>`<button class="nav-item ${state.view===n[0]?'active':''}" data-nav="${n[0]}"><span>${n[1]}</span><span class="nav-label">${n[2]}</span></button>`).join('')}</nav><div class="sidebar-bottom"><div class="streak"><small>Current streak</small><strong>6 days</strong><small>Keep the arc going ↗</small></div><button class="profile profile-button" data-nav="profile"><div class="avatar">${initials(p.name)}</div><div><b>${esc(p.name)}</b><small>${esc(p.year)} · ${esc(p.course.replace('Mathematics ',''))}</small></div><span>›</span></button></div></aside><main class="main"><header class="topbar"><div class="crumb">HSC Mathematics <span style="opacity:.4">/</span> ${nav.find(n=>n[0]===state.view)?.[2]||'Paper'}</div><div class="top-actions"><button class="icon-btn" aria-label="Notifications">◌</button><button class="btn" data-nav="library">Find a paper</button></div></header><div class="content page-enter">${content}</div></main></div>`;bind();}
function paperCard(p){return `<article class="paper-card" data-paper="${p.id}"><div class="paper-top"><span class="pill">${p.course}</span><span class="pill ${p.solution?'solution':''}">${p.solution?'Solutions':'Paper only'}</span></div><h3>${p.school}<br>${p.year} Trial</h3><div class="meta"><span>◷ ${p.minutes} min</span><span>◉ ${p.marks} marks</span></div><div class="card-foot"><div class="topics">${p.topics.map(t=>`<span class="topic">${t}</span>`).join('')}</div><b>→</b></div></article>`}
function home(){let hasResult=Object.keys(state.topicScores).length>0;layout(`<section class="hero"><div class="hero-copy"><div class="eyebrow" style="color:#b8cdc5">Your study space</div><h1>One real paper. A complete practice loop.</h1><p>Start with the Abbotsleigh 2025 Extension 1 trial. Your timer, marking, mistake bank and syllabus map all update from this attempt.</p></div><div class="continue-card"><div><div class="eyebrow">Available now</div><h3>Abbotsleigh<br>2025 Trial</h3><div class="meta" style="color:var(--ink)"><span>Extension 1</span><span>15 questions · 70 marks</span></div><div class="progress"><span style="width:${hasResult?100:0}%"></span></div></div><button class="btn" data-paper="abb25">${hasResult?'Attempt again':'Start fresh attempt'} →</button></div></section><div class="stat-row"><div class="stat-card"><span class="eyebrow">Papers completed</span><strong>${hasResult?1:0}</strong><span class="meta">Abbotsleigh 2025</span></div><div class="stat-card"><span class="eyebrow">Latest mark</span><strong>${hasResult?state.lastScore+' / 70':'—'}</strong><span class="meta">Complete a paper to begin</span></div><div class="stat-card"><span class="eyebrow">Attempt status</span><strong style="font-size:28px">${hasResult?'Marked':'Not started'}</strong><span class="meta">Every new attempt starts blank</span></div><div class="stat-card"><span class="eyebrow">Questions to redo</span><strong>${wrongQuestions.length}</strong><button class="link-btn" data-nav="mistakes">Open question bank</button></div></div><div class="section-head"><div><span class="eyebrow">Paper library</span><h2>Your available paper</h2></div></div><div class="paper-grid single-paper">${paperCard(papers[0])}</div>`)}
function library(){layout(`<div><span class="eyebrow">Past papers</span><h1 class="page-title">The paper library</h1><p class="meta">Complete NSW trial papers with original-paper formatting and worked solutions.</p></div><div class="paper-grid" style="margin-top:25px">${papers.map(paperCard).join('')}</div>`)}
function pdfViewer(file,label){return `<div class="pdf-frame-wrap"><iframe class="pdf-frame" src="${file}#toolbar=1&navpanes=0&view=FitH" title="${label}"></iframe><a class="pdf-open" href="${file}" target="_blank">Open full screen ↗</a></div>`}
function pdfPageViewer(file,page,label){return `<div class="flashcard-pdf"><iframe src="${file}#page=${page}&toolbar=0&navpanes=0&view=FitH" title="${label}"></iframe><a href="${file}#page=${page}" target="_blank" rel="noreferrer">Open page full screen ↗</a></div>`}
function paperAttemptHistory(p){let attempts=state.attemptHistory.filter(attempt=>attempt.paperId===p.id);return `<div class="info-card paper-attempts"><div class="paper-attempt-head"><h3>Past attempts</h3><span>${attempts.length}</span></div>${attempts.length?attempts.map(attempt=>{let pct=Math.round(attempt.score/attempt.max*100),index=state.attemptHistory.indexOf(attempt);return `<div class="paper-attempt-row"><div><b>${attempt.score} / ${attempt.max}</b><small>${pct}% · ${formatDuration(attempt.elapsed)}</small></div><time>${new Date(attempt.completedAt).toLocaleDateString()}</time><button data-delete-attempt="${index}" aria-label="Delete this attempt">×</button></div>`}).join(''):`<p class="meta">No marked attempts for this paper yet.</p>`}</div>`}
function detail(){let p=state.selected,sectionOne=p.sectionOneMarks||10;state.attempt={phase:'idle',startedAt:null,elapsed:0,confirm:false,completed:[]};layout(`<div class="detail-head"><div><span class="eyebrow">Full past paper · ${p.course}</span><h1 class="page-title">${p.school} ${p.year} Trial</h1><div class="meta"><span>◷ ${p.minutes} minutes</span><span>◉ ${p.marks} marks</span><span>▤ ${p.questions} questions</span></div></div><button class="btn" data-start>Start timed attempt →</button></div><div class="full-paper-layout"><section>${pdfViewer(p.paperFile,`${p.school} ${p.year} examination paper`)}</section><aside class="side-panel paper-sidebar"><div class="info-card"><span class="pill">Ready to begin</span><h3 style="margin-top:16px">A clean attempt</h3><p class="meta">All ${p.questions} questions begin undone. Every new result is saved as a separate attempt.</p><button class="btn" style="width:100%;margin-top:14px" data-start>Start ${formatDuration(p.minutes*60)} timer</button></div>${paperAttemptHistory(p)}<div class="info-card"><h3>Exam structure</h3><div class="status-line"><span>Section I</span><b>${sectionOne} marks</b></div><div class="status-line"><span>Section II</span><b>${p.marks-sectionOne} marks</b></div><div class="status-line"><span>Total</span><b>${p.marks} marks</b></div></div><div class="info-card locked-card"><b>◉ Solutions locked</b><p class="meta">Finish the attempt before the worked solutions and marking form become available.</p></div></aside></div>`)}
function formatTime(seconds){let h=Math.floor(seconds/3600),m=Math.floor((seconds%3600)/60),s=seconds%60;return [h,m,s].map(v=>String(v).padStart(2,'0')).join(':')}
function formatDuration(seconds){let hours=Math.floor(seconds/3600),minutes=Math.round((seconds%3600)/60);return hours?`${hours}h ${minutes}m`:`${minutes} min`}
function elapsedNow(){return state.attempt.startedAt?Math.floor((Date.now()-state.attempt.startedAt)/1000)+state.attempt.elapsed:state.attempt.elapsed}
function exam(){let p=state.selected,done=state.attempt.completed.length,questionMarks=p.schema.map(group=>group.total);layout(`<div class="exam-bar"><div><span class="live-dot"></span><div><small>Timed attempt</small><b>${p.school} ${p.year}</b></div></div><div class="timer-block"><small>Elapsed time</small><strong data-timer>${formatTime(elapsedNow())}</strong><span>of ${formatTime(p.minutes*60)}</span></div><button class="btn finish-btn" data-finish>Finish attempt</button></div><div class="exam-layout"><section>${pdfViewer(p.paperFile,`${p.school} ${p.year} examination paper`)}</section><aside class="info-card question-tracker"><div class="tracker-head"><h3>Question tracker</h3><span data-done-count>${done}/${p.questions} done</span></div><p class="meta">Tap a question when you have attempted it.</p><div class="exam-question-grid">${questionMarks.map((max,i)=>`<button class="track-question ${state.attempt.completed.includes(i+1)?'done':''}" data-qprogress="${i+1}"><span>${i+1}</span><small>${max} mark${max===1?'':'s'}</small></button>`).join('')}</div><div class="tracker-tip">Your answers stay on paper. This tracker only records progress.</div></aside></div>${state.attempt.confirm?`<div class="modal-backdrop"><div class="finish-modal"><div class="modal-icon">✓</div><span class="eyebrow">Finish attempt?</span><h2>Ready to mark your paper?</h2><p>Once you finish, the timer stops and the worked solutions unlock. You cannot return to the timed attempt.</p><div><button class="btn secondary" data-cancel-finish>Keep working</button><button class="btn" data-confirm-finish>Finish & unlock solutions</button></div></div></div>`:''}`)}
function markingQuestion(group){return `<article class="mark-question"><header><div><span class="question-number">Question ${group.q}</span><span class="topic-label">${group.parts.map(p=>p.topic).filter((v,i,a)=>a.indexOf(v)===i).slice(0,2).join(' · ')}</span></div><strong><span data-question-score="${group.q}">0</span> / ${group.total}</strong></header><div>${group.parts.map(part=>{let key=`${state.selected.id}:${part.id}`,added=wrongQuestions.some(q=>q.id===key);return `<div class="mark-row"><label for="mark-${part.id}"><b>${part.label}</b><small>${part.topic}</small></label><div><input id="mark-${part.id}" data-mark data-question="${group.q}" data-topic="${part.topic}" type="text" inputmode="numeric" pattern="[0-9]*" data-max="${part.marks}" placeholder="–" aria-label="Mark for Question ${group.q} ${part.label}, maximum ${part.marks}"><span>/ ${part.marks}</span></div><button class="flag-btn ${added?'wrong':''}" data-wrong="${part.id}" aria-label="Add Question ${group.q} ${part.label} to redo">${added?'✓ Added':'Redo'}</button></div>`}).join('')}</div></article>`}
function attempt(){let p=state.selected,sectionI=p.schema.filter(q=>q.section==='I'),sectionII=p.schema.filter(q=>q.section==='II'),sectionOne=p.sectionOneMarks||10;layout(`<div class="detail-head"><div><span class="eyebrow">Attempt complete · Solutions unlocked</span><h1 class="page-title">Mark your paper</h1><div class="meta"><span>${p.school} ${p.year}</span><span>Time: ${formatTime(state.attempt.elapsed)}</span></div></div><div class="score-live"><small>Current score</small><strong><span data-score>0</span> / ${p.marks}</strong></div></div><div class="marking-layout"><section>${pdfViewer(p.solutionFile,`${p.school} ${p.year} worked solutions`)}</section><aside class="panel marking-panel"><h3>Self-marking sheet</h3><p class="meta">Every response part has its own mark field and topic. Values are limited to the marks available.</p><div class="mark-list"><div class="mark-section-title"><span>Section I</span><b>${sectionOne} marks</b></div>${sectionI.map(markingQuestion).join('')}<div class="mark-section-title section-two"><span>Section II</span><b>${p.marks-sectionOne} marks</b></div>${sectionII.map(markingQuestion).join('')}</div><button class="btn save-result" data-save>Save marked result</button></aside></div>`)}
function bankList(items,title,tone){return `<section class="bank-section"><div class="bank-section-head"><div><span class="mastery-dot ${tone}"></span><h2>${title}</h2></div><span>${items.length} question${items.length===1?'':'s'}</span></div><div class="bank-list">${items.map(q=>`<article class="bank-row selectable ${state.bankSelection.includes(q.id)?'selected':''}"><label class="bank-select"><input type="checkbox" data-bank-select="${q.id}" ${state.bankSelection.includes(q.id)?'checked':''}><span></span></label><div class="bank-q"><span>${q.q}</span><small>${q.paper}</small></div><span class="bank-topic">${q.topic}</span><div class="mastery-mini"><div><span style="width:${q.mastery}%"></span></div><b>${q.mastery}%</b></div><span class="attempt-count">${q.attempts} attempt${q.attempts===1?'':'s'}</span><button class="remove-bank" data-remove-bank="${q.id}" aria-label="Remove ${q.q} from question bank">Remove</button><button class="icon-btn" data-study="${wrongQuestions.indexOf(q)}" aria-label="Practise ${q.q}">→</button></article>`).join('')}</div></section>`}
function mistakes(){if(!wrongQuestions.length){state.bankMode='list';layout(`<div class="bank-hero"><div><span class="eyebrow">Personal question bank</span><h1 class="page-title">Your bank is ready.</h1><p>It starts empty. Select <b>Redo</b> while marking either paper to add a question.</p></div></div><div class="empty panel bank-empty"><h3>Zero saved questions</h3><p>Finish and mark a paper to build a bank from your own mistakes.</p><button class="btn" data-nav="library">Choose a paper</button></div>`);return}if(state.bankMode==='list'){let improving=wrongQuestions.filter(q=>q.mastery>=60),needsWork=wrongQuestions.filter(q=>q.mastery<60),average=Math.round(wrongQuestions.reduce((s,q)=>s+q.mastery,0)/wrongQuestions.length),topics=[...new Set(wrongQuestions.map(q=>q.topic))],chosen=state.bankSelection.length;layout(`<div class="bank-hero"><div><span class="eyebrow">Personal question bank</span><h1 class="page-title">Build your own shuffle.</h1><p>Select questions one by one, or click a topic to select every saved question in that area.</p></div><div class="shuffle-actions"><button class="btn secondary" data-select-all>Select all</button><button class="btn shuffle-btn" data-shuffle-selected ${chosen?'':'disabled'}>⤨ Practise selected (${chosen})</button></div></div><div class="topic-selector"><span>Quick select by topic</span>${topics.map(topic=>{let ids=wrongQuestions.filter(q=>q.topic===topic).map(q=>q.id),active=ids.every(id=>state.bankSelection.includes(id));return `<button class="topic-filter ${active?'active':''}" data-select-topic="${topic}">${topic} <b>${ids.length}</b></button>`}).join('')}</div><div class="bank-summary"><div><strong>${wrongQuestions.length}</strong><span>saved questions</span></div><div><strong>${average}%</strong><span>average mastery</span></div><div><strong>${topics.length}</strong><span>NESA areas</span></div></div>${bankList(needsWork,'Needs more work','needs')}${improving.length?bankList(improving,'Improving','improving'):''}`);return}let idx=state.bankOrder[state.flash%state.bankOrder.length],q=wrongQuestions[idx];layout(`<div class="review-top"><button class="btn secondary" data-bank-list>← Question list</button><span class="meta">Selected review · ${state.flash+1} of ${state.bankOrder.length}</span></div><div class="study-card pdf-study-card"><div class="paper-top"><span class="pill">${q.topic}</span><span class="mastery-badge">${q.mastery}% mastery</span></div><h2>${q.q}</h2><span class="meta">${q.paper} · original PDF page ${q.questionPage}</span><p class="card-instruction">Complete the labelled part on paper, using the original exam page below.</p>${pdfPageViewer(q.paperFile,q.questionPage,`${q.q} from the examination paper`)}<div class="answer-box ${state.revealed?'show':''}"><b>Worked solution from the paper</b>${pdfPageViewer(q.solutionFile,q.solutionPage,`${q.q} worked solution`)}</div><div class="study-actions"><span></span>${state.revealed?`<div><button class="btn ghost" data-rate="again">Try again</button> <button class="btn" data-rate="got">Got it →</button></div>`:`<button class="btn" data-reveal>Reveal original solution</button>`}</div></div>`)}
function stats(){let attempts=state.attemptHistory.filter(attempt=>attemptCourse(attempt)===state.statsCourse),entries=Object.keys(state.topicScores),has=attempts.length>0,count=attempts.length,avgPercent=has?attempts.reduce((s,a)=>s+a.score/a.max*100,0)/count:0,avgSeconds=has?Math.round(attempts.reduce((s,a)=>s+a.elapsed,0)/count):0;layout(`<div><span class="eyebrow">Your learning data</span><h1 class="page-title">Every attempt, by course.</h1><p class="meta">Results never mix across Standard, Advanced or Extension courses.</p></div>${resultCourseTabs()}<div class="stat-row"><div class="stat-card"><span class="eyebrow">${state.statsCourse} attempts</span><strong>${count}</strong><span class="meta">Marked papers</span></div><div class="stat-card"><span class="eyebrow">Average mark</span><strong>${has?avgPercent.toFixed(1)+'%':'—'}</strong><span class="meta">This course only</span></div><div class="stat-card"><span class="eyebrow">Questions banked</span><strong>${wrongQuestions.filter(q=>papers.find(p=>p.id===q.paperId)?.course===state.statsCourse).length}</strong><button class="link-btn" data-nav="mistakes">View question bank</button></div><div class="stat-card"><span class="eyebrow">Average time per paper</span><strong>${has?formatDuration(avgSeconds):'—'}</strong><span class="meta">${state.statsCourse} papers</span></div></div>${has?`<section class="panel attempt-history"><div class="section-head compact"><div><span class="eyebrow">${state.statsCourse}</span><h2>Marks and time</h2></div></div><div class="attempt-chart">${attempts.map(attempt=>{let paper=papers.find(p=>p.id===attempt.paperId),pct=Math.round(attempt.score/attempt.max*100),date=new Date(attempt.completedAt),index=state.attemptHistory.indexOf(attempt);return `<article class="attempt-result"><div class="attempt-bar-wrap"><span class="attempt-bar" style="height:${Math.max(8,pct)}%"></span><b>${pct}%</b></div><div><strong>${attempt.score} / ${attempt.max}</strong><span>${formatDuration(attempt.elapsed)}</span><small>${paper?.school||'Past paper'} ${paper?.year||''} · ${date.toLocaleDateString()}</small></div><button class="delete-attempt" data-delete-attempt="${index}" aria-label="Delete this attempt">Delete</button></article>`}).join('')}</div></section><div class="panel" style="margin-top:18px"><h3>${state.statsCourse} syllabus-area performance</h3>${entries.map(area=>{let pct=areaPercent(area);return `<div class="topic-row"><span>${area}</span><div class="topic-track"><span style="width:${pct}%"></span></div><b>${pct}%</b></div>`}).join('')}</div>`:`<div class="empty panel" style="margin-top:18px"><h3>No ${state.statsCourse} results yet</h3><p>Complete and mark a ${state.statsCourse} paper to build this course’s statistics.</p><button class="btn" data-nav="library">Choose a paper</button></div>`}`)}
function syllabusCourseBlock(course){let data=syllabusAreas[course],isAdded=course!==state.profile.course,version=state.profile.year==='Year 12'&&/Advanced|Extension/.test(course)?`${course} Stage 6 Syllabus (2017)`:data.version;return `<section class="syllabus-course-block"><div class="course-block-head"><div><span class="pill ${isAdded?'':'solution'}">${isAdded?'Required with your course':'Selected course'}</span><h2>${course}</h2></div><small>${version}</small></div><div class="area-grid">${data.areas.map(area=>{let percent=areaPercent(area),status=percent===null?'No paper data':percent>=75?'Strong':percent>=50?'Improving':'Needs work';return `<article class="area-card score-area ${percent===null?'no-score':''}"><div class="area-title"><h3>${area}</h3><b>${percent===null?'—':percent+'%'}</b></div><div class="area-progress"><span style="width:${percent??0}%"></span></div><p>${status}</p><i class="${status==='Strong'?'is-strong':status==='Improving'?'is-improving':percent===null?'':'is-needs'}"></i></article>`}).join('')}</div></section>`}
function syllabus(){let p=state.profile,s=syllabusFor(p),hasData=Object.keys(state.topicScores).length>0,courseKey={'Extension 1':'Mathematics Extension 1','Extension 2':'Mathematics Extension 2','Advanced':'Mathematics Advanced','Standard 2':'Mathematics Standard 2','Standard 1':'Mathematics Standard 1'}[state.statsCourse]||'Mathematics Advanced';let transition=p.year==='Year 11'?'2024 syllabus · first taught in 2026':p.year==='Year 12'?'2017 syllabus · current 2026 HSC cohort':'Mathematics K–10 Syllabus (2022)';layout(`<div class="syllabus-hero"><div><span class="eyebrow">NESA aligned · ${transition}</span><h1 class="page-title">Your syllabus map.</h1><p>Course results are kept separate so an Extension paper cannot change Advanced or Standard statistics.</p></div><div class="syllabus-seal">NSW<br><b>2026</b></div></div>${resultCourseTabs()}<div class="syllabus-layout"><main class="panel syllabus-main"><div class="map-explainer"><div><span class="pill solution">${state.statsCourse} performance</span><h2>${hasData?'Built only from '+state.statsCourse+' attempts':'Ready for your first '+state.statsCourse+' result'}</h2><p>${hasData?'Each percentage uses marks earned in this course only.':'Finish and mark a '+state.statsCourse+' paper to populate this map.'}</p></div><div class="map-legend"><span><i class="strong"></i>Strong</span><span><i class="improving"></i>Improving</span><span><i class="needs"></i>Needs work</span></div></div>${syllabusCourseBlock(courseKey)}</main><aside class="side-panel"><div class="info-card"><h3>Your enrolled course stack</h3>${s.courses.map((course,i)=>`<div class="stack-course"><span>${i+1}</span><div><b>${course.replace('Mathematics ','')}</b><small>${course===p.course?'Selected':'NESA prerequisite / corequisite'}</small></div></div>`).join('')}</div><div class="info-card"><h3>How separation works</h3><p class="meta">Marks from ${state.statsCourse} papers contribute only to the ${state.statsCourse} map and averages.</p></div><a class="btn secondary syllabus-link" href="${NESA_SOURCE}" target="_blank" rel="noreferrer">View NESA source ↗</a></aside></div>`)}
function profile(){let p=state.profile,s=syllabusFor(p),topics=s.areas;layout(`<div class="profile-heading"><div><span class="eyebrow">Student profile</span><h1 class="page-title">Make Arc yours.</h1><p class="meta">Your goals help Arc recommend the right papers and revision questions.</p></div><div class="profile-orbit"><div class="avatar avatar-large">${initials(p.name)}</div><span></span><span></span></div></div><form class="profile-layout" data-profile-form><section class="panel profile-form"><div class="form-section"><h3>About you</h3><p class="meta">Choose your highest mathematics course. Arc automatically includes every NESA prerequisite and corequisite.</p><div class="form-grid"><label class="field"><span>Full name</span><input name="name" value="${esc(p.name)}" required maxlength="60" placeholder="Your name"></label><label class="field"><span>Year group</span><select name="year">${['Year 9','Year 10','Year 11','Year 12'].map(y=>`<option ${p.year===y?'selected':''}>${y}</option>`).join('')}</select></label><label class="field field-wide"><span>Highest NESA course</span><select name="course">${coursesForYear(p.year).map(c=>`<option ${p.course===c?'selected':''}>${c}</option>`).join('')}</select><small>${esc(s.version)}</small></label></div><div class="course-includes"><span>Your course stack</span>${s.courses.map((course,i)=>`<b>${i?'＋':''} ${course.replace('Mathematics ','')}</b>`).join('')}</div></div><div class="form-section"><h3>Learning goals</h3><p class="meta">Give yourself a finish line worth running toward.</p><div class="form-grid"><label class="field field-wide"><span>Main goal</span><textarea name="goal" maxlength="180" placeholder="What would you like to achieve?">${esc(p.goal)}</textarea><small><span data-count>${p.goal.length}</span>/180 characters</small></label><label class="field field-wide"><span>Weekly practice target</span><select name="weekly">${['1 paper per week','2 papers per week','3 papers per week','4 papers per week','5+ papers per week'].map(w=>`<option ${p.weekly===w?'selected':''}>${w}</option>`).join('')}</select></label></div></div><div class="form-section"><h3>NESA focus areas</h3><p class="meta">These include every area from your complete course stack.</p><div class="focus-grid">${topics.map(t=>`<label class="focus-chip"><input type="checkbox" name="focus" value="${t}" ${p.focus.includes(t)?'checked':''}><span>${t}</span></label>`).join('')}</div></div><div class="form-actions"><span class="save-note">Saved only on this device</span><button class="btn" type="submit">Save profile</button></div></section><aside class="profile-preview"><div class="goal-card"><span class="eyebrow">Your north star</span><blockquote>“${esc(p.goal)}”</blockquote><div class="goal-meta"><span>${esc(p.year)}</span><span>${esc(p.weekly)}</span></div></div><div class="info-card"><h3>NESA course rules</h3><div class="benefit"><i>01</i><div><b>Extension 1 includes Advanced</b><p>Extension 1 extends the Mathematics Advanced course.</p></div></div><div class="benefit"><i>02</i><div><b>Extension 2 includes both</b><p>Advanced and Extension 1 are prerequisites and corequisites.</p></div></div><div class="benefit"><i>03</i><div><b>One combined map</b><p>Your results roll up across every course you study.</p></div></div></div></aside></form>`)}
function beginAttempt(){clearInterval(timerInterval);state.attempt={phase:'running',startedAt:Date.now(),elapsed:0,confirm:false,completed:[]};state.view='exam';render();timerInterval=setInterval(()=>{let timer=document.querySelector('[data-timer]');if(timer)timer.textContent=formatTime(elapsedNow())},1000);toast('Timer started. All questions are undone.')}
function bind(){
 document.querySelectorAll('[data-nav]').forEach(el=>el.onclick=()=>{clearInterval(timerInterval);state.view=el.dataset.nav;if(state.view==='mistakes')state.bankMode='list';state.revealed=false;render()});
 document.querySelectorAll('[data-paper]').forEach(el=>el.onclick=()=>{state.selected=papers.find(p=>p.id===el.dataset.paper);state.view='detail';render()});
 document.querySelectorAll('[data-filter]').forEach(el=>el.onclick=()=>{state.filter=el.dataset.filter;library()});
 let s=document.querySelector('.search');if(s)s.oninput=e=>{state.search=e.target.value;library()};
 document.querySelectorAll('[data-start]').forEach(el=>el.onclick=beginAttempt);
 document.querySelectorAll('[data-qprogress]').forEach(el=>el.onclick=()=>{let q=Number(el.dataset.qprogress),index=state.attempt.completed.indexOf(q);if(index>=0)state.attempt.completed.splice(index,1);else state.attempt.completed.push(q);el.classList.toggle('done');let counter=document.querySelector('[data-done-count]');if(counter)counter.textContent=`${state.attempt.completed.length}/${state.selected.questions} done`});
 let finish=document.querySelector('[data-finish]');if(finish)finish.onclick=()=>{state.attempt.confirm=true;exam()};
 let cancelFinish=document.querySelector('[data-cancel-finish]');if(cancelFinish)cancelFinish.onclick=()=>{state.attempt.confirm=false;exam()};
 let confirmFinish=document.querySelector('[data-confirm-finish]');if(confirmFinish)confirmFinish.onclick=()=>{state.attempt.elapsed=elapsedNow();state.attempt.startedAt=null;state.attempt.phase='marking';state.attempt.confirm=false;clearInterval(timerInterval);state.view='attempt';render();toast('Attempt finished. Solutions are now unlocked.')};
 let source=document.querySelector('[data-source]');if(source)source.onclick=()=>window.open(SOURCE,'_blank','noopener');
 let reveal=document.querySelector('[data-reveal]');if(reveal)reveal.onclick=()=>{state.revealed=true;mistakes()};
 document.querySelectorAll('[data-bank-select]').forEach(el=>el.onchange=()=>{let id=el.dataset.bankSelect,index=state.bankSelection.indexOf(id);if(el.checked&&index<0)state.bankSelection.push(id);if(!el.checked&&index>=0)state.bankSelection.splice(index,1);mistakes()});
 document.querySelectorAll('[data-remove-bank]').forEach(el=>el.onclick=()=>{let id=el.dataset.removeBank,index=wrongQuestions.findIndex(q=>q.id===id);if(index>=0)wrongQuestions.splice(index,1);state.bankSelection=state.bankSelection.filter(selected=>selected!==id);persistLearningData();mistakes();toast('Question removed from your bank.')});
 let selectAll=document.querySelector('[data-select-all]');if(selectAll)selectAll.onclick=()=>{state.bankSelection=state.bankSelection.length===wrongQuestions.length?[]:wrongQuestions.map(q=>q.id);mistakes()};
 document.querySelectorAll('[data-select-topic]').forEach(el=>el.onclick=()=>{let ids=wrongQuestions.filter(q=>q.topic===el.dataset.selectTopic).map(q=>q.id),all=ids.every(id=>state.bankSelection.includes(id));state.bankSelection=all?state.bankSelection.filter(id=>!ids.includes(id)):[...new Set([...state.bankSelection,...ids])];mistakes()});
 let shuffle=document.querySelector('[data-shuffle-selected]');if(shuffle)shuffle.onclick=()=>{state.bankOrder=state.bankSelection.map(id=>wrongQuestions.findIndex(q=>q.id===id)).filter(i=>i>=0);for(let i=state.bankOrder.length-1;i>0;i--){let j=Math.floor(Math.random()*(i+1));[state.bankOrder[i],state.bankOrder[j]]=[state.bankOrder[j],state.bankOrder[i]]}state.flash=0;state.revealed=false;state.bankMode='study';mistakes()};
 document.querySelectorAll('[data-study]').forEach(el=>el.onclick=()=>{let chosen=Number(el.dataset.study);state.bankOrder=[chosen];state.flash=0;state.revealed=false;state.bankMode='study';mistakes()});
 let bankListButton=document.querySelector('[data-bank-list]');if(bankListButton)bankListButton.onclick=()=>{state.bankMode='list';state.revealed=false;mistakes()};
 document.querySelectorAll('[data-rate]').forEach(el=>el.onclick=()=>{let question=wrongQuestions[state.bankOrder[state.flash%state.bankOrder.length]];question.attempts++;question.mastery=Math.max(0,Math.min(100,question.mastery+(el.dataset.rate==='got'?8:-5)));persistLearningData();state.flash=(state.flash+1)%state.bankOrder.length;state.revealed=false;mistakes();toast(el.dataset.rate==='got'?'Nice. That area is improving.':'No stress — it’ll come back sooner.')});
 document.querySelectorAll('[data-wrong]').forEach(el=>el.onclick=()=>{let partId=el.dataset.wrong,key=`${state.selected.id}:${partId}`,isAdded=el.classList.toggle('wrong'),existing=wrongQuestions.findIndex(q=>q.id===key);el.textContent=isAdded?'✓ Added':'Redo';if(isAdded&&existing<0){let group=state.selected.schema.find(g=>g.parts.some(p=>p.id===partId)),part=group.parts.find(p=>p.id===partId),pages=sourcePages(state.selected,group.q,part);wrongQuestions.push({id:key,paperId:state.selected.id,paper:`${state.selected.school} ${state.selected.year}`,paperFile:state.selected.paperFile,solutionFile:state.selected.solutionFile,q:`Question ${group.q} ${part.label==='Multiple choice'||part.label===`Question ${group.q}`?'':part.label}`.trim(),topic:topicArea(part.topic,state.selected.course),mastery:0,attempts:0,...pages})}if(!isAdded&&existing>=0){wrongQuestions.splice(existing,1);state.bankSelection=state.bankSelection.filter(id=>id!==key)}persistLearningData()});
 document.querySelectorAll('[data-mark]').forEach(el=>{el.oninput=()=>{let raw=el.value.replace(/\D/g,''),max=Number(el.dataset.max),clamped=raw!==''&&Number(raw)>max;el.value=raw===''?'':String(Math.min(Number(raw),max));let all=[...document.querySelectorAll('[data-mark]')],total=all.reduce((sum,input)=>sum+(Number(input.value)||0),0),score=document.querySelector('[data-score]');if(score)score.textContent=total;let q=el.dataset.question,subtotal=all.filter(input=>input.dataset.question===q).reduce((sum,input)=>sum+(Number(input.value)||0),0),qScore=document.querySelector(`[data-question-score="${q}"]`);if(qScore)qScore.textContent=subtotal;if(clamped){el.classList.add('mark-clamped');setTimeout(()=>el.classList.remove('mark-clamped'),450);toast(`Maximum for this part is ${max}.`)}}});
 let save=document.querySelector('[data-save]');if(save)save.onclick=()=>{let inputs=[...document.querySelectorAll('[data-mark]')],scores={};inputs.forEach(input=>{let area=topicArea(input.dataset.topic,state.selected.course),max=Number(input.dataset.max),earned=Number(input.value)||0;if(!scores[area])scores[area]={earned:0,max:0};scores[area].earned+=earned;scores[area].max+=max});state.lastScore=inputs.reduce((sum,input)=>sum+(Number(input.value)||0),0);state.attemptHistory.push({id:crypto.randomUUID?.()||String(Date.now()),paperId:state.selected.id,course:state.selected.course,score:state.lastScore,max:state.selected.marks,elapsed:state.attempt.elapsed,completedAt:new Date().toISOString(),topicScores:scores});state.statsCourse=state.selected.course;rebuildTopicScores();persistLearningData();state.view='stats';render();toast('Attempt saved to your '+state.statsCourse+' statistics.')};
 document.querySelectorAll('[data-delete-attempt]').forEach(el=>el.onclick=()=>{state.attemptHistory.splice(Number(el.dataset.deleteAttempt),1);rebuildTopicScores();persistLearningData();render();toast('Attempt deleted from your history.')});
 document.querySelectorAll('[data-stats-course]').forEach(el=>el.onclick=()=>{state.statsCourse=el.dataset.statsCourse;rebuildTopicScores();render()});
 let ai=document.querySelector('[data-ai]');if(ai)ai.onclick=()=>toast('AI tutor is ready for a backend connection.');
 let form=document.querySelector('[data-profile-form]');if(form){let goal=form.elements.goal,count=document.querySelector('[data-count]'),year=form.elements.year,course=form.elements.course;goal.oninput=()=>count.textContent=goal.value.length;year.onchange=()=>{course.innerHTML=coursesForYear(year.value).map(c=>`<option>${c}</option>`).join('');toast('Courses updated for '+year.value)};form.onsubmit=e=>{e.preventDefault();let data=new FormData(form);state.profile={name:data.get('name').trim(),year:data.get('year'),course:data.get('course'),goal:data.get('goal').trim(),weekly:data.get('weekly'),focus:data.getAll('focus')};localStorage.setItem('arc-profile',JSON.stringify(state.profile));profile();toast('Profile saved — syllabus updated.')}}
}
function toast(msg){let t=document.createElement('div');t.className='toast';t.textContent=msg;document.body.append(t);setTimeout(()=>t.remove(),2600)}
function render(){({home,library,mistakes,stats,detail,exam,attempt,syllabus,profile}[state.view]||home)()};render();
